import java.util.*;

class ThroneInheritance {
    Map<String, List<String>> children = new HashMap<>();
    Map<String, Boolean> alive = new HashMap<>();
    String king;

    public ThroneInheritance(String kingName) {
        king = kingName;
        alive.put(kingName, true);
    }

    public void birth(String parentName, String childName) {
        children.computeIfAbsent(parentName, k -> new ArrayList<>()).add(childName);
        alive.put(childName, true);
    }

    public void death(String name) {
        alive.put(name, false);
    }

    public List<String> getInheritanceOrder() {
        List<String> order = new ArrayList<>();
        getSuccessor(king, order);
        return order;
    }

    private void getSuccessor(String name, List<String> order) {
        if (alive.get(name)) {
            order.add(name);
        }
        for (String child : children.getOrDefault(name, new ArrayList<>())) {
            getSuccessor(child, order);
        }
    }
}
```

